    override fun get_scope_identifier(): String {
        return scope_identifier
    }

    override fun set_scope_identifier(identifier: String?) {
        scope_identifier = identifier ?: ""
    }

    private fun zzRefill(): Boolean {
        if (zzStartRead > 0) {
            System.arraycopy(zzBuffer, zzStartRead, zzBuffer, 0, zzEndRead - zzStartRead)
            zzEndRead -= zzStartRead
            zzCurrentPos -= zzStartRead
            zzMarkedPos -= zzStartRead
            zzPushbackPos -= zzStartRead
            zzStartRead = 0
        }

        if (zzCurrentPos >= zzBuffer.size) {
            val newBuffer = CharArray(zzCurrentPos * 2)
            System.arraycopy(zzBuffer, 0, newBuffer, 0, zzBuffer.size)
            zzBuffer = newBuffer
        }

        val reader = zzReader ?: return true
        val numRead = reader.read(zzBuffer, zzEndRead, zzBuffer.size - zzEndRead)

        return if (numRead < 0) {
            true
        } else {
            zzEndRead += numRead
            false
        }
    }

    fun yyclose() {
        zzAtEOF = true
        zzEndRead = zzStartRead
        zzReader?.close()
    }

    fun yyreset(reader: Reader) {
        zzReader = reader
        zzAtBOL = true
        zzAtEOF = false
        zzStartRead = 0
        zzEndRead = 0
        zzCurrentPos = 0
        zzMarkedPos = 0
        zzPushbackPos = 0
        yyline = 0
        yychar = 0
        yycolumn = 0
        zzLexicalState = YYINITIAL
    }

    fun yystate(): Int {
        return zzLexicalState
    }

    override fun yybegin(newState: Int) {
        zzLexicalState = newState
    }

    fun yytext(): String {
        return String(zzBuffer, zzStartRead, zzMarkedPos - zzStartRead)
    }

    fun yycharat(pos: Int): Char {
        return zzBuffer[zzStartRead + pos]
    }

    fun yylength(): Int {
        return zzMarkedPos - zzStartRead
    }

    private fun zzScanError(errorCode: Int) {
        val message = when (errorCode) {
            ZZ_UNKNOWN_ERROR -> "Unkown internal scanner error"
            ZZ_NO_MATCH -> "Error: could not match input"
            ZZ_PUSHBACK_2BIG -> "Error: pushback value was too large"
            else -> "Unkown internal scanner error"
        }
        throw Error(message)
    }

    fun yypushback(number: Int) {
        if (number > yylength()) {
            zzScanError(ZZ_PUSHBACK_2BIG)
        }
        zzMarkedPos -= number
    }

