    override fun next_string(): String {
        return next_string(false, ' ')
    }

    override fun next_string(ignoreNewline: Boolean): String {
        return next_string(ignoreNewline, ' ')
    }

    fun next_string(ignoreNewline: Boolean, leading: Char): String {
        stringBuffer.setLength(0)
        var i = 0

        val skipLeading = ArrayList<Char>()
        if (ignoreNewline) {
            skipLeading.addAll(stringSkipTrailingNewLines)
        } else {
            skipLeading.addAll(stringSkipTrailing)
        }
        skipLeading.add(leading)

        while (zzMarkedPos + i < zzBuffer.size && skipLeading.contains(zzBuffer[zzMarkedPos + i])) {
            i++
        }

        if (zzMarkedPos + i >= zzBuffer.size) {
            return ""
        }

        var skipLastChar = false
        val stopAt = ArrayList<Char>()
        if (zzBuffer[zzMarkedPos + i] == '"') {
            stopAt.addAll(stringStopAtQuotes)
            i++
            skipLastChar = true
        } else {
            stopAt.addAll(stringStopAt)
            stopAt.add(leading)
        }

        // read the actual string until we have a space/tab/new line
        while (zzMarkedPos + i < zzBuffer.size && !stopAt.contains(zzBuffer[zzMarkedPos + i])) {
            stringBuffer.append(zzBuffer[zzMarkedPos + i])
            i++
        }

        if (skipLastChar) {
            i++
        }

        if (i > 0) {
            zzStartRead += i - 1
            zzCurrentPos += i - 1
            zzMarkedPos += i
            zzLexicalState = YYINITIAL

            if (zzMarkedPos > 0 && (zzBuffer[zzMarkedPos - 1] == '(' || zzBuffer[zzMarkedPos - 1] == ')')) {
                // if the string ended with brackets, we need to step back one character, because we need
                // that bracket as the next token
                zzStartRead--
                zzCurrentPos--
                zzMarkedPos--
            }
        }

        return stringBuffer.toString()
    }

    override fun next_string_list(): Array<String> {
        return next_string_list(' ')
    }

    override fun next_string_list(separator: Char): Array<String> {
        val result = LinkedList<String>()

        val first_string = next_string(true, separator)
        if (first_string.isNotEmpty()) {
            result.add(first_string)
        }

        while (true) {
            val next_string = next_string(true, separator)
            if (next_string.isEmpty()) {
                break
            }
            result.add(next_string)
        }

        zzStartRead = zzMarkedPos - 1
        zzCurrentPos = zzMarkedPos - 1

        return result.toTypedArray()
    }

    override fun next_double(): Double? {
        val s = next_string()
        if (nf == null) {
            nf = NumberFormat.getInstance(Locale.US)
        }
        return try {
            nf!!.parse(s).toDouble()
        } catch (_: ParseException) {
            null
        }
    }

    override fun next_closing_bracket(): Boolean {
        val nextToken = try {
            next_token()
        } catch (e: IOException) {
            FRLogger.error("Network.read_net_pins: IO error scanning file", e)
            return false
        }
        if (nextToken == null) {
            FRLogger.warn("Network.read_net_pins: unexpected end of file")
            return false
        }
        if (nextToken != Keyword.CLOSED_BRACKET) {
            FRLogger.warn("Network.read_net_pins: expected closed bracket is missing")
            return false
        }
        return true
    }
}
